    <style>
        :root {
            --blue-primary: #2563eb;
            --blue-dark: #1e40af;
            --blue-light: #eff6ff;
        }

        body {
            font-family: 'Plus Jakarta Sans', sans-serif;
            /* === Wallpaper foto laundry === */
            background-image:
                /* Overlay: gelap di atas foto agar teks tetap terbaca */
                linear-gradient(
                    160deg,
                    rgba(15, 23, 60, 0.72) 0%,
                    rgba(30, 64, 175, 0.60) 40%,
                    rgba(15, 23, 60, 0.75) 100%
                ),
                url('data:image/jpeg;base64,');
            background-size: cover;
            background-position: center center;
            background-attachment: fixed;
            background-repeat: no-repeat;
        }

        .glass-nav {
            background: rgba(10, 20, 60, 0.65);
            backdrop-filter: blur(18px);
            -webkit-backdrop-filter: blur(18px);
            border-bottom-color: rgba(255,255,255,0.10) !important;
        }
        .glass-nav .text-blue-900  { color: #fff !important; }
        .glass-nav .text-blue-600  { color: #93c5fd !important; }
        .glass-nav .text-slate-600 { color: #cbd5e1 !important; }

        /* ── Hero transparent so body bg shows ── */
        .hero-bg {
            background: transparent;
        }

        /* ── Floating bubbles ── */
        .bubble {
            position: absolute;
            border-radius: 50%;
            background: rgba(37,99,235,0.06);
            animation: floatBubble linear infinite;
            pointer-events: none;
        }
        @keyframes floatBubble {
            0%   { transform: translateY(0) scale(1); opacity: 0.5; }
            50%  { transform: translateY(-40px) scale(1.05); opacity: 0.7; }
            100% { transform: translateY(0) scale(1); opacity: 0.5; }
        }

        /* ── Fade-in on load ── */
        @keyframes fadeUp {
            from { opacity: 0; transform: translateY(30px); }
            to   { opacity: 1; transform: translateY(0); }
        }
        .fade-up { animation: fadeUp 0.7s ease both; }
        .delay-1 { animation-delay: 0.15s; }
        .delay-2 { animation-delay: 0.30s; }
        .delay-3 { animation-delay: 0.45s; }
        .delay-4 { animation-delay: 0.60s; }

        /* ── Stat card hover glow ── */
        .stat-card {
            transition: transform 0.3s ease, box-shadow 0.3s ease;
        }
        .stat-card:hover {
            transform: translateY(-6px);
            box-shadow: 0 20px 40px -12px rgba(37,99,235,0.18);
        }

        /* ── Feature card ── */
        .feature-card {
            transition: transform 0.35s cubic-bezier(.22,.68,0,1.2), box-shadow 0.35s ease, border-color 0.35s ease;
            background: linear-gradient(145deg, #ffffff 0%, #f8faff 100%);
        }
        .feature-card:hover {
            transform: translateY(-10px);
            box-shadow: 0 32px 60px -16px rgba(37,99,235,0.15);
            border-color: rgba(37,99,235,0.20);
        }
        .feature-icon {
            transition: background 0.3s ease, transform 0.3s ease, box-shadow 0.3s ease;
        }
        .feature-card:hover .feature-icon {
            background: linear-gradient(135deg, #2563eb, #4f46e5);
            transform: scale(1.1) rotate(-4deg);
            box-shadow: 0 12px 28px -6px rgba(37,99,235,0.45);
        }

        /* ── Step connector line ── */
        .step-line::after {
            content: '';
            position: absolute;
            top: 2rem;
            left: calc(100% + 1px);
            width: calc(100% - 2px);
            height: 2px;
            background: linear-gradient(90deg, #2563eb, transparent);
            opacity: 0.25;
        }

        /* ── Gradient text ── */
        .gradient-text {
            background: linear-gradient(135deg, #1d4ed8 0%, #4f46e5 100%);
            -webkit-background-clip: text;
            background-clip: text;
            -webkit-text-fill-color: transparent;
        }

        /* ── Button shine ── */
        .btn-primary {
            background: linear-gradient(135deg, #2563eb 0%, #3b4fde 100%);
            box-shadow: 0 8px 24px -6px rgba(37,99,235,0.50);
            transition: transform 0.2s ease, box-shadow 0.2s ease, filter 0.2s ease;
            position: relative;
            overflow: hidden;
        }
        .btn-primary::after {
            content: '';
            position: absolute;
            inset: 0;
            background: linear-gradient(90deg, transparent 0%, rgba(255,255,255,0.18) 50%, transparent 100%);
            transform: translateX(-100%);
            transition: transform 0.5s ease;
        }
        .btn-primary:hover::after { transform: translateX(100%); }
        .btn-primary:hover {
            transform: translateY(-3px);
            box-shadow: 0 16px 36px -8px rgba(37,99,235,0.55);
            filter: brightness(1.06);
        }

        .btn-outline {
            transition: transform 0.2s ease, box-shadow 0.2s ease, background 0.2s ease;
        }
        .btn-outline:hover {
            transform: translateY(-3px);
            box-shadow: 0 12px 28px -8px rgba(0,0,0,0.10);
            background: #f8faff;
        }

        /* ── Noise texture overlay on footer ── */
        .footer-texture {
            position: relative;
            background: linear-gradient(160deg, #0f172a 0%, #1e1b4b 100%);
        }

        /* ── Scroll-reveal ── */
        .reveal {
            opacity: 0;
            transform: translateY(28px);
            transition: opacity 0.6s ease, transform 0.6s ease;
        }
        .reveal.visible {
            opacity: 1;
            transform: none;
        }

        /* ── Divider wave ── */
        .wave-divider svg { display: block; }

        /* ── Tag pill ── */
        .badge-pill {
            background: linear-gradient(90deg, #eff6ff, #eef2ff);
            border: 1px solid rgba(37,99,235,0.18);
        }
    </style>
</head>
